```
#! /usr/bin/env python
#! -*- coding:utf-8 -*-
import angr
import claripy

proj = angr.Project('./level07')

arg1 = claripy.BVS('sym_arg', 8 * 11)
arg2 = claripy.BVS('sym_arg', 8 * 44)


init_state = proj.factory.entry_state(args=['./level07', arg1, arg2])
init_state.libc.max_strtol_len = 11


smgr = proj.factory.simgr(init_state)


smgr.explore(find=lambda sm: "WIN" in sm.state.posix.dumps(1))

if (len(smgr.found) > 0):
    sol_state = smgr.found[0]
    print "arg1 = {} ".format(repr(sol_state.se.eval(arg1,cast_to=str)))
    print "arg2 = {} ".format(repr(sol_state.se.eval(arg2,cast_to=str)))
